LIBRARY IEEE;
USE IEEE.STD_LOGIC_1164.ALL;
USE IEEE.NUMERIC_STD.ALL;
USE IEEE.MATH_REAL.ALL;

ENTITY generic_reg_file IS
    GENERIC (
        GC_DATA_WIDTH : INTEGER := 32; -- Width of each register
        GC_NUM_REGS : INTEGER := 8 -- Number of registers
    );
    PORT (
        clk, rst : IN STD_LOGIC;

        -- Write port
        write_en : IN STD_LOGIC;
        write_addr : IN STD_LOGIC_VECTOR(INTEGER(CEIL(LOG2(REAL(GC_NUM_REGS)))) - 1 DOWNTO 0);
        write_data : IN STD_LOGIC_VECTOR(GC_DATA_WIDTH - 1 DOWNTO 0);

        -- Read port 1
        read_addr1 : IN STD_LOGIC_VECTOR(INTEGER(CEIL(LOG2(REAL(GC_NUM_REGS)))) - 1 DOWNTO 0);
        read_data1 : OUT STD_LOGIC_VECTOR(GC_DATA_WIDTH - 1 DOWNTO 0);

        -- Read port 2
        read_addr2 : IN STD_LOGIC_VECTOR(INTEGER(CEIL(LOG2(REAL(GC_NUM_REGS)))) - 1 DOWNTO 0);
        read_data2 : OUT STD_LOGIC_VECTOR(GC_DATA_WIDTH - 1 DOWNTO 0)
    );
END ENTITY generic_reg_file;

ARCHITECTURE rtl OF generic_reg_file IS
    -- Register array type
    TYPE reg_array_t IS ARRAY (0 TO GC_NUM_REGS - 1) OF STD_LOGIC_VECTOR(GC_DATA_WIDTH - 1 DOWNTO 0);

    -- Register storage
    SIGNAL registers : reg_array_t;

BEGIN
    -- Write process
    write_proc : PROCESS (clk, rst)
    BEGIN
        IF rst = '0' THEN
            -- Reset all registers to 0
            FOR i IN 0 TO GC_NUM_REGS - 1 LOOP
                registers(i) <= (OTHERS => '0');
            END LOOP;
        ELSIF rising_edge(clk) THEN
            IF write_en = '1' THEN
                registers(TO_INTEGER(UNSIGNED(write_addr))) <= write_data;
            END IF;
        END IF;
    END PROCESS;

    -- Read port 1 (combinational)
    read_data1 <= registers(TO_INTEGER(UNSIGNED(read_addr1)));

    -- Read port 2 (combinational)
    read_data2 <= registers(TO_INTEGER(UNSIGNED(read_addr2)));

END ARCHITECTURE rtl;

