LIBRARY ieee;
USE ieee.std_logic_1164.ALL;
USE std.textio.ALL;
USE ieee.numeric_std.ALL;
USE ieee.math_real.ALL;
USE work.constants.ALL;

ENTITY decode_stage IS
    PORT (

        clk : IN STD_LOGIC;
        rst : IN STD_LOGIC;
        -- inputs
        sp_wb_data_in : IN STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0); -- from wb stage
        wb_data : IN STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0);   -- from wb stage
        wb_addr : IN STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0);
        reg_write_en : IN STD_LOGIC;
        --sel
        sp_wb_sel : IN STD_LOGIC;

        -- instruction fetch stage inputs
        instr_in : IN STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0); -- from if/id reg 
        pc_in : IN STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0);
	    id_ex_imm_op: IN STD_LOGIC;
        ---------------------------------------
        -- Control signals outputs
        ---------------------------------------
        -- Swap flag input
        swap_flag_in : IN STD_LOGIC;
        ccr_wb_out : OUT STD_LOGIC;
        imm_op_out : OUT STD_LOGIC;
        call_out : OUT STD_LOGIC;
        r2_sel_out : OUT STD_LOGIC;
        sp_type_out : OUT STD_LOGIC;
        sp_wb_out : OUT STD_LOGIC;
        swap_out : OUT STD_LOGIC;
        wb_sel_out : OUT STD_LOGIC_VECTOR(1 DOWNTO 0);
        mem_write_out : OUT STD_LOGIC;
        mem_read_out : OUT STD_LOGIC;
        io_write_out : OUT STD_LOGIC;
        pc_from_memory_out : OUT STD_LOGIC;
        write_data_sel_out : OUT STD_LOGIC_VECTOR(1 DOWNTO 0);
        io_read_out : OUT STD_LOGIC;
        reg_write_out : OUT STD_LOGIC;
        is_std_out : OUT STD_LOGIC;
        is_branch_out : OUT STD_LOGIC;
        branch_type_out : OUT STD_LOGIC;
        stall_out : OUT STD_LOGIC;

        -- reg_dist_sel : IN STD_LOGIC;   FROM CONTROL DIRECTLY

        -- outputs to execute stage
        instr_funct : OUT STD_LOGIC_VECTOR(4 DOWNTO 0); -- to alu control unit 
        pc_out : OUT STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0);
        sp_out : OUT STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0);
        imm_ext_out : OUT STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0);
        -- for forwarding 
        rsrs1 : OUT STD_LOGIC_VECTOR((REG_ADDR_WIDTH - 1) DOWNTO 0); -- to id/ex stage
        rdst : OUT STD_LOGIC_VECTOR((REG_ADDR_WIDTH - 1) DOWNTO 0); -- to id/ex stage

        index_ext_out : OUT STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0);-- to id/ex stage
        r_data1 : OUT STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0);
        r_data2 : OUT STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0);
        dest: OUT STD_LOGIC_VECTOR((REG_ADDR_WIDTH - 1) DOWNTO 0)
    );
END ENTITY decode_stage;

ARCHITECTURE rtl OF decode_stage IS

    COMPONENT reg_file IS
        GENERIC (
            GC_DATA_WIDTH : INTEGER := 32; -- Width of each register
            GC_NUM_REGS : INTEGER := 8 -- Number of registers
        );
        PORT (
            clk : IN STD_LOGIC;
            reset : IN STD_LOGIC;

            -- Write port
            write_en : IN STD_LOGIC;
            write_addr : IN STD_LOGIC_VECTOR(INTEGER(CEIL(LOG2(REAL(GC_NUM_REGS)))) - 1 DOWNTO 0);
            write_data : IN STD_LOGIC_VECTOR(GC_DATA_WIDTH - 1 DOWNTO 0);

            -- Read port 1
            read_addr1 : IN STD_LOGIC_VECTOR(INTEGER(CEIL(LOG2(REAL(GC_NUM_REGS)))) - 1 DOWNTO 0);
            read_data1 : OUT STD_LOGIC_VECTOR(GC_DATA_WIDTH - 1 DOWNTO 0);

            -- Read port 2
            read_addr2 : IN STD_LOGIC_VECTOR(INTEGER(CEIL(LOG2(REAL(GC_NUM_REGS)))) - 1 DOWNTO 0);
            read_data2 : OUT STD_LOGIC_VECTOR(GC_DATA_WIDTH - 1 DOWNTO 0)
        );
    END COMPONENT;

    COMPONENT control_unit IS 
        PORT (
            clk             : IN  STD_LOGIC;
            rst             : IN  STD_LOGIC;
            opcode          : IN  STD_LOGIC_VECTOR(4 DOWNTO 0);
            swap_flag       : IN  STD_LOGIC;

            ccr_wb          : OUT STD_LOGIC;
            imm_op           : OUT STD_LOGIC;
            call            : OUT STD_LOGIC;
            r2_sel           : OUT STD_LOGIC;
            sp_type         : OUT STD_LOGIC;
            sp_wb           : OUT STD_LOGIC;
            swap            : OUT STD_LOGIC;
            wb_sel           : OUT STD_LOGIC_VECTOR(1 DOWNTO 0);
            mem_write        : OUT STD_LOGIC;
            mem_read         : OUT STD_LOGIC;
            io_write         : OUT STD_LOGIC;
            pc_from_memory  : OUT STD_LOGIC;
            write_data_sel  : OUT STD_LOGIC_VECTOR(1 DOWNTO 0);
            io_read          : OUT STD_LOGIC;
            reg_write       : OUT STD_LOGIC;
            is_std          : OUT STD_LOGIC;
            reg_dst          : OUT STD_LOGIC;
            is_branch        : OUT STD_LOGIC;
            branch_type     : OUT STD_LOGIC;
            stall           : OUT STD_LOGIC;
	        operand2_address_sel : OUT STD_LOGIC
        );
    END COMPONENT;

    -- Internal signals
    SIGNAL sp_reg : STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0);
    SIGNAL sp_next : STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0);
    SIGNAL Rd2 : STD_LOGIC_VECTOR((REG_ADDR_WIDTH - 1) DOWNTO 0);

    -- Control signals from control unit (before muxing)
    SIGNAL cu_ccr_wb : STD_LOGIC;
    SIGNAL cu_imm_op : STD_LOGIC;
    SIGNAL cu_call : STD_LOGIC;
    SIGNAL cu_r2_sel : STD_LOGIC;
    SIGNAL cu_sp_type : STD_LOGIC;
    SIGNAL cu_sp_wb : STD_LOGIC;
    SIGNAL cu_swap : STD_LOGIC;
    SIGNAL cu_wb_sel : STD_LOGIC_VECTOR(1 DOWNTO 0);
    SIGNAL cu_mem_write : STD_LOGIC;
    SIGNAL cu_mem_read : STD_LOGIC;
    SIGNAL cu_io_write : STD_LOGIC;
    SIGNAL cu_pc_from_memory : STD_LOGIC;
    SIGNAL cu_write_data_sel : STD_LOGIC_VECTOR(1 DOWNTO 0);
    SIGNAL cu_io_read : STD_LOGIC;
    SIGNAL cu_reg_write : STD_LOGIC;
    SIGNAL cu_is_std : STD_LOGIC;
    SIGNAL cu_reg_dst : STD_LOGIC;  -- OR REG_DST_OUT
    SIGNAL cu_is_branch : STD_LOGIC;
    SIGNAL cu_branch_type : STD_LOGIC;
    SIGNAL cu_stall : STD_LOGIC;
    SIGNAL cu_operand2_address_sel : STD_LOGIC;

    -- Output signals
    SIGNAL reg_dst_out : STD_LOGIC;
    SIGNAL operand2_address_sel_out : STD_LOGIC;

    -- Hazard detection signals
    SIGNAL control_signals_sel : STD_LOGIC;
    SIGNAL if_id_write_int : STD_LOGIC;
    SIGNAL pc_write_int : STD_LOGIC;
BEGIN

    -- SP Register Process
    sp_register : PROCESS (clk)
    BEGIN
        IF rising_edge(clk) THEN
            IF rst = '0' THEN
                sp_reg <= (OTHERS => '0');
            ELSE
                sp_reg <= sp_wb_data_in;
            END IF;
        END IF;
    END PROCESS;

    dest <= instr_in(26 DOWNTO 24) when reg_dst_out = '1' else instr_in(20 DOWNTO 18);  -- 1 or 0
    Rd2 <= instr_in(26 DOWNTO 24) when operand2_address_sel_out = '1' else instr_in(20 DOWNTO 18);

    -- Register File Instance
    reg_file_inst : reg_file
    GENERIC MAP(
        GC_DATA_WIDTH => WORD_SIZE,
        GC_NUM_REGS => NUM_REGS
        )
        PORT MAP(
        clk => clk,
        reset => rst, -- active low reset

        write_en => reg_write_en,
        write_addr => wb_addr(REG_ADDR_WIDTH - 1 DOWNTO 0),
        write_data => wb_data,

        read_addr1 => instr_in(23 DOWNTO 21), -- rs1 bits
        read_data1 => r_data1, --- to id/ex stage

        read_addr2 => Rd2, -- rs2 bits
        read_data2 => r_data2 --- to id/ex stage
        );

        control_unit_inst : control_unit 
        PORT MAP(
            clk => clk,
        rst => rst,
        opcode => instr_in(31 DOWNTO 27),
        swap_flag => swap_flag_in,
        ccr_wb => cu_ccr_wb,
        imm_op => cu_imm_op,
        call => cu_call,
        r2_sel => cu_r2_sel,
        sp_type => cu_sp_type,
        sp_wb => cu_sp_wb,
        swap => cu_swap,
        wb_sel => cu_wb_sel,
        mem_write => cu_mem_write,
        mem_read => cu_mem_read,
        io_write => cu_io_write,
        pc_from_memory => cu_pc_from_memory,
        write_data_sel => cu_write_data_sel,
        io_read => cu_io_read,
        reg_write => cu_reg_write,
        is_std => cu_is_std,
        reg_dst => cu_reg_dst,
        is_branch => cu_is_branch,
        branch_type => cu_branch_type,
        stall => cu_stall,
        operand2_address_sel => cu_operand2_address_sel
        );

    -- When control_signals_sel = '1', insert NOP (all control signals = 0)
    -- When control_signals_sel = '0', use normal control unit outputs
    ccr_wb_out <= '0' WHEN control_signals_sel = '1' OR id_ex_imm_op = '1' ELSE cu_ccr_wb;
    imm_op_out <= '0' WHEN control_signals_sel = '1' OR id_ex_imm_op = '1' ELSE cu_imm_op;
    call_out <= '0' WHEN control_signals_sel = '1' OR id_ex_imm_op = '1' ELSE cu_call;
    r2_sel_out <= '0' WHEN control_signals_sel = '1' OR id_ex_imm_op = '1' ELSE cu_r2_sel;
    sp_type_out <= '0' WHEN control_signals_sel = '1' OR id_ex_imm_op = '1' ELSE cu_sp_type;
    sp_wb_out <= '0' WHEN control_signals_sel = '1' OR id_ex_imm_op = '1' ELSE cu_sp_wb;
    swap_out <= '0' WHEN control_signals_sel = '1' OR id_ex_imm_op = '1' ELSE cu_swap;
    wb_sel_out <= "00" WHEN control_signals_sel = '1' OR id_ex_imm_op = '1' ELSE cu_wb_sel;
    mem_write_out <= '0' WHEN control_signals_sel = '1' OR id_ex_imm_op = '1' ELSE cu_mem_write;
    mem_read_out <= '0' WHEN control_signals_sel = '1' OR id_ex_imm_op = '1' ELSE cu_mem_read;
    io_write_out <= '0' WHEN control_signals_sel = '1' OR id_ex_imm_op = '1' ELSE cu_io_write;
    pc_from_memory_out <= '0' WHEN control_signals_sel = '1' OR id_ex_imm_op = '1' ELSE cu_pc_from_memory;
    write_data_sel_out <= "00" WHEN control_signals_sel = '1' OR id_ex_imm_op = '1' ELSE cu_write_data_sel;
    io_read_out <= '0' WHEN control_signals_sel = '1' OR id_ex_imm_op = '1' ELSE cu_io_read;
    reg_write_out <= '0' WHEN control_signals_sel = '1' OR id_ex_imm_op = '1' ELSE cu_reg_write;
    is_std_out <= '0' WHEN control_signals_sel = '1' OR id_ex_imm_op = '1' ELSE cu_is_std;
    reg_dst_out <= '0' WHEN control_signals_sel = '1' OR id_ex_imm_op = '1' ELSE cu_reg_dst;
    is_branch_out <= '0' WHEN control_signals_sel = '1' OR id_ex_imm_op = '1' ELSE cu_is_branch;
    branch_type_out <= '0' WHEN control_signals_sel = '1' OR id_ex_imm_op = '1' ELSE cu_branch_type;
    stall_out <= '0' WHEN control_signals_sel = '1' OR id_ex_imm_op = '1' ELSE cu_stall;
    operand2_address_sel_out <= '0' WHEN control_signals_sel = '1' OR id_ex_imm_op = '1' ELSE cu_operand2_address_sel;

    -- Sign extend immediate
    imm_ext_out <= STD_LOGIC_VECTOR(resize(signed(instr_in(15 DOWNTO 0)), WORD_SIZE));
    -- extend index
    index_ext_out <= (WORD_SIZE-1 downto 1 => '0') & instr_in(0); --- 0 ??? or 27
    -- Output the current SP value (read immedaitely)
    sp_out <= sp_reg;
    rdst <= Rd2;
    -- Pass through instruction and PC
    instr_funct <= instr_in(4 DOWNTO 0); -- to id/ex stage
    pc_out <= pc_in; -- to id/ex stage
    rsrs1 <= instr_in(23 DOWNTO 21);
END ARCHITECTURE rtl;

