--------------------------------------------------------------------------------
-- Testbench: decode_stage_tb.vhd
-- Tests:
--   1. SP register read and write
--   2. Register file read and write
--   3. No operation (NOP)
--   4. Normal control signals
--------------------------------------------------------------------------------

LIBRARY ieee;
USE ieee.std_logic_1164.ALL;
USE ieee.numeric_std.ALL;
USE work.constants.ALL;

ENTITY decode_stage_tb IS
END ENTITY decode_stage_tb;

ARCHITECTURE tb OF decode_stage_tb IS

    -- Clock period
    CONSTANT CLK_PERIOD : TIME := 10 ns;

    -- Component declaration
    COMPONENT decode_stage IS
        PORT (
            clk             : IN STD_LOGIC;
            rst             : IN STD_LOGIC;
            sp_wb_data_in   : IN STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0);
            wb_data         : IN STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0);
            wb_addr         : IN STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0);
            reg_write_en    : IN STD_LOGIC;
            sp_wb_sel       : IN STD_LOGIC;
            instr_in        : IN STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0);
            pc_in           : IN STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0);
            id_ex_imm_op    : IN STD_LOGIC;
            swap_flag_in    : IN STD_LOGIC;

            ccr_wb_out          : OUT STD_LOGIC;
            imm_op_out          : OUT STD_LOGIC;
            call_out            : OUT STD_LOGIC;
            r2_sel_out          : OUT STD_LOGIC;
            sp_type_out         : OUT STD_LOGIC;
            sp_wb_out           : OUT STD_LOGIC;
            swap_out            : OUT STD_LOGIC;
            wb_sel_out          : OUT STD_LOGIC_VECTOR(1 DOWNTO 0);
            mem_write_out       : OUT STD_LOGIC;
            mem_read_out        : OUT STD_LOGIC;
            io_write_out        : OUT STD_LOGIC;
            pc_from_memory_out  : OUT STD_LOGIC;
            write_data_sel_out  : OUT STD_LOGIC_VECTOR(1 DOWNTO 0);
            io_read_out         : OUT STD_LOGIC;
            reg_write_out       : OUT STD_LOGIC;
            is_std_out          : OUT STD_LOGIC;
            reg_dst_out         : OUT STD_LOGIC;
            is_branch_out       : OUT STD_LOGIC;
            branch_type_out     : OUT STD_LOGIC;
            stall_out           : OUT STD_LOGIC;
            instr_funct         : OUT STD_LOGIC_VECTOR(4 DOWNTO 0);
            pc_out              : OUT STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0);
            sp_out              : OUT STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0);
            imm_ext_out         : OUT STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0);
            rsrs1               : OUT STD_LOGIC_VECTOR((REG_ADDR_WIDTH - 1) DOWNTO 0);
            rdst                : OUT STD_LOGIC_VECTOR((REG_ADDR_WIDTH - 1) DOWNTO 0);
            index_ext_out       : OUT STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0);
            r_data1             : OUT STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0);
            r_data2             : OUT STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0);
            dest                : OUT STD_LOGIC_VECTOR((REG_ADDR_WIDTH - 1) DOWNTO 0)
        );
    END COMPONENT;

    -- Testbench signals
    SIGNAL clk              : STD_LOGIC := '0';
    SIGNAL rst              : STD_LOGIC := '0';
    SIGNAL sp_wb_data_in    : STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0) := (OTHERS => '0');
    SIGNAL wb_data          : STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0) := (OTHERS => '0');
    SIGNAL wb_addr          : STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0) := (OTHERS => '0');
    SIGNAL reg_write_en     : STD_LOGIC := '0';
    SIGNAL sp_wb_sel        : STD_LOGIC := '0';
    SIGNAL instr_in         : STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0) := (OTHERS => '0');
    SIGNAL pc_in            : STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0) := (OTHERS => '0');
    SIGNAL id_ex_imm_op     : STD_LOGIC := '0';
    SIGNAL swap_flag_in     : STD_LOGIC := '0';

    -- Output signals
    SIGNAL ccr_wb_out           : STD_LOGIC;
    SIGNAL imm_op_out           : STD_LOGIC;
    SIGNAL call_out             : STD_LOGIC;
    SIGNAL r2_sel_out           : STD_LOGIC;
    SIGNAL sp_type_out          : STD_LOGIC;
    SIGNAL sp_wb_out            : STD_LOGIC;
    SIGNAL swap_out             : STD_LOGIC;
    SIGNAL wb_sel_out           : STD_LOGIC_VECTOR(1 DOWNTO 0);
    SIGNAL mem_write_out        : STD_LOGIC;
    SIGNAL mem_read_out         : STD_LOGIC;
    SIGNAL io_write_out         : STD_LOGIC;
    SIGNAL pc_from_memory_out   : STD_LOGIC;
    SIGNAL write_data_sel_out   : STD_LOGIC_VECTOR(1 DOWNTO 0);
    SIGNAL io_read_out          : STD_LOGIC;
    SIGNAL reg_write_out        : STD_LOGIC;
    SIGNAL is_std_out           : STD_LOGIC;
    SIGNAL reg_dst_out          : STD_LOGIC;
    SIGNAL is_branch_out        : STD_LOGIC;
    SIGNAL branch_type_out      : STD_LOGIC;
    SIGNAL stall_out            : STD_LOGIC;
    SIGNAL instr_funct          : STD_LOGIC_VECTOR(4 DOWNTO 0);
    SIGNAL pc_out               : STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0);
    SIGNAL sp_out               : STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0);
    SIGNAL imm_ext_out          : STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0);
    SIGNAL rsrs1                : STD_LOGIC_VECTOR((REG_ADDR_WIDTH - 1) DOWNTO 0);
    SIGNAL rdst                 : STD_LOGIC_VECTOR((REG_ADDR_WIDTH - 1) DOWNTO 0);
    SIGNAL index_ext_out        : STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0);
    SIGNAL r_data1              : STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0);
    SIGNAL r_data2              : STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0);
    SIGNAL dest                 : STD_LOGIC_VECTOR((REG_ADDR_WIDTH - 1) DOWNTO 0);

    -- Test tracking
    SIGNAL test_done : BOOLEAN := FALSE;

    -- Helper function to build instruction
    -- Instruction format: [31:27]=opcode, [26:24]=Rdst, [23:21]=Rsrc1, [20:18]=Rsrc2, [15:0]=imm
    FUNCTION build_instruction(
        opcode : STD_LOGIC_VECTOR(4 DOWNTO 0);
        rdst   : STD_LOGIC_VECTOR(2 DOWNTO 0);
        rsrc1  : STD_LOGIC_VECTOR(2 DOWNTO 0);
        rsrc2  : STD_LOGIC_VECTOR(2 DOWNTO 0);
        func   : STD_LOGIC_VECTOR(4 DOWNTO 0);
        imm    : STD_LOGIC_VECTOR(15 DOWNTO 0)
    ) RETURN STD_LOGIC_VECTOR IS
        VARIABLE instr : STD_LOGIC_VECTOR(31 DOWNTO 0);
    BEGIN
        instr := opcode & rdst & rsrc1 & rsrc2 & "00" & imm(15 DOWNTO 5) & func;
        RETURN instr;
    END FUNCTION;

BEGIN

    -- Clock generation
    clk_process : PROCESS
    BEGIN
        WHILE NOT test_done LOOP
            clk <= '0';
            WAIT FOR CLK_PERIOD / 2;
            clk <= '1';
            WAIT FOR CLK_PERIOD / 2;
        END LOOP;
        WAIT;
    END PROCESS;

    -- DUT instantiation
    DUT : decode_stage
    PORT MAP (
        clk                 => clk,
        rst                 => rst,
        sp_wb_data_in       => sp_wb_data_in,
        wb_data             => wb_data,
        wb_addr             => wb_addr,
        reg_write_en        => reg_write_en,
        sp_wb_sel           => sp_wb_sel,
        instr_in            => instr_in,
        pc_in               => pc_in,
        id_ex_imm_op        => id_ex_imm_op,
        swap_flag_in        => swap_flag_in,
        ccr_wb_out          => ccr_wb_out,
        imm_op_out          => imm_op_out,
        call_out            => call_out,
        r2_sel_out          => r2_sel_out,
        sp_type_out         => sp_type_out,
        sp_wb_out           => sp_wb_out,
        swap_out            => swap_out,
        wb_sel_out          => wb_sel_out,
        mem_write_out       => mem_write_out,
        mem_read_out        => mem_read_out,
        io_write_out        => io_write_out,
        pc_from_memory_out  => pc_from_memory_out,
        write_data_sel_out  => write_data_sel_out,
        io_read_out         => io_read_out,
        reg_write_out       => reg_write_out,
        is_std_out          => is_std_out,
        reg_dst_out         => reg_dst_out,
        is_branch_out       => is_branch_out,
        branch_type_out     => branch_type_out,
        stall_out           => stall_out,
        instr_funct         => instr_funct,
        pc_out              => pc_out,
        sp_out              => sp_out,
        imm_ext_out         => imm_ext_out,
        rsrs1               => rsrs1,
        rdst                => rdst,
        index_ext_out       => index_ext_out,
        r_data1             => r_data1,
        r_data2             => r_data2,
        dest                => dest
    );

    -- Stimulus process
    stim_proc : PROCESS
    BEGIN
        -- Initial reset (active low)
        rst <= '0';
        WAIT FOR 2 * CLK_PERIOD;
        rst <= '1';  -- Release reset
        WAIT FOR CLK_PERIOD;

        ------------------------------------------------------------------------
        -- TEST 1: SP Register Read and Write
        ------------------------------------------------------------------------
        REPORT "========== TEST 1: SP Register Read and Write ==========" SEVERITY NOTE;

        -- Write value to SP register
        sp_wb_data_in <= X"0000ABCD";
        WAIT FOR CLK_PERIOD;

        -- Verify SP output
        ASSERT sp_out = X"0000ABCD"
            REPORT "SP Write Test FAILED: Expected 0x0000ABCD, got " & 
                   TO_STRING(sp_out)
            SEVERITY ERROR;

        -- Update SP to a new value
        sp_wb_data_in <= X"00001234";
        WAIT FOR CLK_PERIOD;

        ASSERT sp_out = X"00001234"
            REPORT "SP Update Test FAILED: Expected 0x00001234, got " & 
                   TO_STRING(sp_out)
            SEVERITY ERROR;

        REPORT "TEST 1: SP Register Read/Write - PASSED" SEVERITY NOTE;

        ------------------------------------------------------------------------
        -- TEST 2: Register File Read and Write
        ------------------------------------------------------------------------
        REPORT "========== TEST 2: Register File Read and Write ==========" SEVERITY NOTE;

        -- Write to R1 via writeback
        reg_write_en <= '1';
        wb_addr <= X"00000001";  -- R1 address
        wb_data <= X"DEADBEEF";
        WAIT FOR CLK_PERIOD;

        -- Write to R2 via writeback
        wb_addr <= X"00000002";  -- R2 address
        wb_data <= X"CAFEBABE";
        WAIT FOR CLK_PERIOD;

        -- Write to R3 via writeback
        wb_addr <= X"00000003";  -- R3 address
        wb_data <= X"12345678";
        WAIT FOR CLK_PERIOD;

        reg_write_en <= '0';

        -- Read R1 and R2 using instruction (NOP with register addresses set)
        -- Format: instr_in[23:21] = rsrc1. instr_in[20:18] = rsrc2
        instr_in <= OPC_NOP & "000" & "001" & "010" & "00" & "00000000000" & "00000";
        WAIT FOR CLK_PERIOD / 2;  -- Wait for combinational read

        ASSERT r_data1 = X"DEADBEEF"
            REPORT "Register R1 Read FAILED: Expected 0xDEADBEEF, got " & 
                   TO_STRING(r_data1)
            SEVERITY ERROR;

        -- Note: For NOP, rdst is used based on operand2_address_sel which is '0' for NOP
        -- So it reads from Rsrc2 field (bits 20:18)
        ASSERT r_data2 = X"CAFEBABE"
            REPORT "Register R2 Read FAILED: Expected 0xCAFEBABE, got " & 
                   TO_STRING(r_data2)
            SEVERITY ERROR;

        -- Read R3 via Rsrc1 field
        instr_in <= OPC_NOP & "000" & "011" & "001" & "00" & "00000000000" & "00000";
        WAIT FOR CLK_PERIOD / 2;

        ASSERT r_data1 = X"12345678"
            REPORT "Register R3 Read FAILED: Expected 0x12345678, got " & 
                   TO_STRING(r_data1)
            SEVERITY ERROR;

        REPORT "TEST 2: Register File Read/Write - PASSED" SEVERITY NOTE;
        WAIT FOR CLK_PERIOD / 2;

        ------------------------------------------------------------------------
        -- TEST 3: No Operation (NOP)
        ------------------------------------------------------------------------
        REPORT "========== TEST 3: No Operation (NOP) ==========" SEVERITY NOTE;

        -- Issue NOP instruction (opcode = 00000)
        instr_in <= OPC_NOP & "000" & "000" & "000" & "00" & "00000000000" & "00000";
        id_ex_imm_op <= '0';
        WAIT FOR CLK_PERIOD / 2;

        -- NOP should not set reg_write, mem_write, mem_read, etc.
        ASSERT reg_write_out = '0'
            REPORT "NOP Test FAILED: reg_write should be 0"
            SEVERITY ERROR;

        ASSERT mem_write_out = '0'
            REPORT "NOP Test FAILED: mem_write should be 0"
            SEVERITY ERROR;

        ASSERT mem_read_out = '0'
            REPORT "NOP Test FAILED: mem_read should be 0"
            SEVERITY ERROR;

        ASSERT is_branch_out = '0'
            REPORT "NOP Test FAILED: is_branch should be 0"
            SEVERITY ERROR;

        ASSERT stall_out = '0'
            REPORT "NOP Test FAILED: stall should be 0"
            SEVERITY ERROR;

        ASSERT ccr_wb_out = '0'
            REPORT "NOP Test FAILED: ccr_wb should be 0"
            SEVERITY ERROR;

        REPORT "TEST 3: No Operation (NOP) - PASSED" SEVERITY NOTE;
        WAIT FOR CLK_PERIOD / 2;

        ------------------------------------------------------------------------
        -- TEST 4: Normal Control Signals
        ------------------------------------------------------------------------
        REPORT "========== TEST 4: Normal Control Signals ==========" SEVERITY NOTE;

        -- Test 4a: ALU Operation (ADD R1, R2, R3)
        REPORT "Test 4a: ALU ADD instruction" SEVERITY NOTE;
        instr_in <= OPC_ALU & "001" & "010" & "011" & "00" & "00000000000" & FUNC_ADD;
        swap_flag_in <= '0';
        WAIT FOR CLK_PERIOD / 2;

        ASSERT ccr_wb_out = '1'
            REPORT "ALU ADD: ccr_wb should be 1"
            SEVERITY ERROR;
        ASSERT reg_write_out = '1'
            REPORT "ALU ADD: reg_write should be 1"
            SEVERITY ERROR;
        ASSERT reg_dst_out = '0'
            REPORT "ALU ADD: reg_dst should be 0 for ALU ops"
            SEVERITY ERROR;
        ASSERT wb_sel_out = "00"
            REPORT "ALU ADD: wb_sel should be 00 (ALU result)"
            SEVERITY ERROR;
        ASSERT imm_op_out = '0'
            REPORT "ALU ADD: imm_op should be 0"
            SEVERITY ERROR;

        WAIT FOR CLK_PERIOD / 2;

        -- Test 4b: IADD (Immediate Add) - R1 = R2 + imm
        REPORT "Test 4b: IADD instruction" SEVERITY NOTE;
        instr_in <= OPC_IADD & "001" & "010" & "000" & "00" & "0000000000000100" ; -- imm = 4
        WAIT FOR CLK_PERIOD / 2;

        ASSERT imm_op_out = '1'
            REPORT "IADD: imm_op should be 1"
            SEVERITY ERROR;
        ASSERT r2_sel_out = '1'
            REPORT "IADD: r2_sel should be 1"
            SEVERITY ERROR;
        ASSERT reg_write_out = '1'
            REPORT "IADD: reg_write should be 1"
            SEVERITY ERROR;
        ASSERT reg_dst_out = '1'
            REPORT "IADD: reg_dst should be 1"
            SEVERITY ERROR;

        WAIT FOR CLK_PERIOD / 2;

        -- Test 4c: PUSH instruction
        REPORT "Test 4c: PUSH instruction" SEVERITY NOTE;
        instr_in <= OPC_PUSH & "001" & "000" & "000" & "00" & "00000000000" & "00000";
        WAIT FOR CLK_PERIOD / 2;

        ASSERT sp_type_out = '1'
            REPORT "PUSH: sp_type should be 1"
            SEVERITY ERROR;
        ASSERT sp_wb_out = '1'
            REPORT "PUSH: sp_wb should be 1"
            SEVERITY ERROR;
        ASSERT mem_write_out = '1'
            REPORT "PUSH: mem_write should be 1"
            SEVERITY ERROR;
        ASSERT reg_write_out = '0'
            REPORT "PUSH: reg_write should be 0"
            SEVERITY ERROR;

        WAIT FOR CLK_PERIOD / 2;

        -- Test 4d: POP instruction
        REPORT "Test 4d: POP instruction" SEVERITY NOTE;
        instr_in <= OPC_POP & "001" & "000" & "000" & "00" & "00000000000" & "00000";
        WAIT FOR CLK_PERIOD / 2;

        ASSERT sp_wb_out = '1'
            REPORT "POP: sp_wb should be 1"
            SEVERITY ERROR;
        ASSERT mem_read_out = '1'
            REPORT "POP: mem_read should be 1"
            SEVERITY ERROR;
        ASSERT reg_write_out = '1'
            REPORT "POP: reg_write should be 1"
            SEVERITY ERROR;
        ASSERT wb_sel_out = "10"
            REPORT "POP: wb_sel should be 10 (from memory)"
            SEVERITY ERROR;

        WAIT FOR CLK_PERIOD / 2;

        -- Test 4e: LDM (Load Immediate) instruction
        REPORT "Test 4e: LDM instruction" SEVERITY NOTE;
        instr_in <= OPC_LDM & "001" & "000" & "000" & "00" & "1111111111111111"; -- imm = -1 (0xFFFF)
        WAIT FOR CLK_PERIOD / 2;

        ASSERT imm_op_out = '1'
            REPORT "LDM: imm_op should be 1"
            SEVERITY ERROR;
        ASSERT reg_write_out = '1'
            REPORT "LDM: reg_write should be 1"
            SEVERITY ERROR;
        ASSERT wb_sel_out = "01"
            REPORT "LDM: wb_sel should be 01 (immediate)"
            SEVERITY ERROR;
        -- Check sign extension (16-bit 0xFFFF should extend to 32-bit 0xFFFFFFFF)
        ASSERT imm_ext_out = X"FFFFFFFF"
            REPORT "LDM: imm_ext_out should be sign-extended to 0xFFFFFFFF, got " &
                   TO_STRING(imm_ext_out)
            SEVERITY ERROR;

        WAIT FOR CLK_PERIOD / 2;

        -- Test 4f: JMP instruction
        REPORT "Test 4f: JMP instruction" SEVERITY NOTE;
        instr_in <= OPC_JMP & "000" & "001" & "000" & "00" & "0000000000001000"; -- target in imm
        WAIT FOR CLK_PERIOD / 2;

        ASSERT is_branch_out = '1'
            REPORT "JMP: is_branch should be 1"
            SEVERITY ERROR;
        ASSERT branch_type_out = '0'
            REPORT "JMP: branch_type should be 0 (unconditional)"
            SEVERITY ERROR;
        ASSERT imm_op_out = '1'
            REPORT "JMP: imm_op should be 1"
            SEVERITY ERROR;

        WAIT FOR CLK_PERIOD / 2;

        -- Test 4g: CALL instruction
        REPORT "Test 4g: CALL instruction" SEVERITY NOTE;
        instr_in <= OPC_CALL & "000" & "001" & "000" & "00" & "0000000000010000"; -- target in imm
        WAIT FOR CLK_PERIOD / 2;

        ASSERT call_out = '1'
            REPORT "CALL: call should be 1"
            SEVERITY ERROR;
        ASSERT is_branch_out = '1'
            REPORT "CALL: is_branch should be 1"
            SEVERITY ERROR;
        ASSERT sp_type_out = '1'
            REPORT "CALL: sp_type should be 1 (push PC)"
            SEVERITY ERROR;
        ASSERT mem_write_out = '1'
            REPORT "CALL: mem_write should be 1"
            SEVERITY ERROR;

        WAIT FOR CLK_PERIOD / 2;

        -- Test 4h: IN instruction
        REPORT "Test 4h: IN instruction" SEVERITY NOTE;
        instr_in <= OPC_IN & "010" & "000" & "000" & "00" & "00000000000" & "00000";
        WAIT FOR CLK_PERIOD / 2;

        ASSERT io_read_out = '1'
            REPORT "IN: io_read should be 1"
            SEVERITY ERROR;
        ASSERT reg_write_out = '1'
            REPORT "IN: reg_write should be 1"
            SEVERITY ERROR;

        WAIT FOR CLK_PERIOD / 2;

        -- Test 4i: OUT instruction
        REPORT "Test 4i: OUT instruction" SEVERITY NOTE;
        instr_in <= OPC_OUT & "000" & "010" & "000" & "00" & "00000000000" & "00000";
        WAIT FOR CLK_PERIOD / 2;

        ASSERT io_write_out = '1'
            REPORT "OUT: io_write should be 1"
            SEVERITY ERROR;
        ASSERT reg_write_out = '0'
            REPORT "OUT: reg_write should be 0"
            SEVERITY ERROR;

        WAIT FOR CLK_PERIOD / 2;

        -- Test 4j: NOT instruction
        REPORT "Test 4j: NOT instruction" SEVERITY NOTE;
        instr_in <= OPC_NOT & "001" & "010" & "000" & "00" & "00000000000" & "00000";
        WAIT FOR CLK_PERIOD / 2;

        ASSERT ccr_wb_out = '1'
            REPORT "NOT: ccr_wb should be 1"
            SEVERITY ERROR;
        ASSERT reg_write_out = '1'
            REPORT "NOT: reg_write should be 1"
            SEVERITY ERROR;

        WAIT FOR CLK_PERIOD / 2;

        -- Test 4k: INC instruction
        REPORT "Test 4k: INC instruction" SEVERITY NOTE;
        instr_in <= OPC_INC & "001" & "010" & "000" & "00" & "00000000000" & "00000";
        WAIT FOR CLK_PERIOD / 2;

        ASSERT ccr_wb_out = '1'
            REPORT "INC: ccr_wb should be 1"
            SEVERITY ERROR;
        ASSERT reg_write_out = '1'
            REPORT "INC: reg_write should be 1"
            SEVERITY ERROR;

        WAIT FOR CLK_PERIOD / 2;

        -- Test 4l: HLT instruction (should stall)
        REPORT "Test 4l: HLT instruction" SEVERITY NOTE;
        instr_in <= OPC_HLT & "000" & "000" & "000" & "00" & "00000000000" & "00000";
        WAIT FOR CLK_PERIOD / 2;

        ASSERT stall_out = '1'
            REPORT "HLT: stall should be 1"
            SEVERITY ERROR;

        WAIT FOR CLK_PERIOD / 2;

        REPORT "TEST 4: Normal Control Signals - PASSED" SEVERITY NOTE;

        ------------------------------------------------------------------------
        -- TEST 5: Control Signal Muxing with id_ex_imm_op
        ------------------------------------------------------------------------
        REPORT "========== TEST 5: Control Signal Muxing ==========" SEVERITY NOTE;

        -- When id_ex_imm_op = '1', all control outputs should be zeroed
        instr_in <= OPC_ALU & "001" & "010" & "011" & "00" & "00000000000" & FUNC_ADD;
        id_ex_imm_op <= '1';
        WAIT FOR CLK_PERIOD / 2;

        ASSERT ccr_wb_out = '0'
            REPORT "Mux Test: ccr_wb should be 0 when id_ex_imm_op=1"
            SEVERITY ERROR;
        ASSERT reg_write_out = '0'
            REPORT "Mux Test: reg_write should be 0 when id_ex_imm_op=1"
            SEVERITY ERROR;
        ASSERT mem_write_out = '0'
            REPORT "Mux Test: mem_write should be 0 when id_ex_imm_op=1"
            SEVERITY ERROR;

        id_ex_imm_op <= '0';
        WAIT FOR CLK_PERIOD / 2;

        REPORT "TEST 5: Control Signal Muxing - PASSED" SEVERITY NOTE;

        ------------------------------------------------------------------------
        -- End of tests
        ------------------------------------------------------------------------
        REPORT "========================================" SEVERITY NOTE;
        REPORT "ALL TESTS COMPLETED SUCCESSFULLY" SEVERITY NOTE;
        REPORT "========================================" SEVERITY NOTE;

        test_done <= TRUE;
        WAIT;
    END PROCESS;

END ARCHITECTURE tb;

examples.after_code:
--------------------------------------------------------------------------------
-- Testbench: decode_stage_tb.vhd
-- Tests:
--   1. SP register read and write
--   2. Register file read and write
--   3. No operation (NOP)
--   4. Normal control signals
--------------------------------------------------------------------------------

LIBRARY ieee;
USE ieee.std_logic_1164.ALL;
USE ieee.numeric_std.ALL;
USE work.constants.ALL;

ENTITY decode_stage_tb IS
END ENTITY decode_stage_tb;

ARCHITECTURE tb OF decode_stage_tb IS

    -- Clock period
    CONSTANT CLK_PERIOD : TIME := 10 ns;

    -- Component declaration (updated to match new decode_stage interface)
    COMPONENT decode_stage IS
        PORT (
            clk                 : IN STD_LOGIC;
            rst                 : IN STD_LOGIC;
            sp_wb_data_in       : IN STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0);
            wb_data             : IN STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0);
            wb_addr             : IN STD_LOGIC_VECTOR(REG_ADDR_WIDTH - 1 DOWNTO 0);
            reg_write_en        : IN STD_LOGIC;
            sp_wb_sel           : IN STD_LOGIC;
            instr_in            : IN STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0);
            pc_in               : IN STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0);
            id_ex_imm_op        : IN STD_LOGIC;
            control_signals_sel : IN STD_LOGIC;  -- FROM HAZARD DETECTION
            swap_flag_in        : IN STD_LOGIC;

            ccr_wb_out          : OUT STD_LOGIC;
            imm_op_out          : OUT STD_LOGIC;
            call_out            : OUT STD_LOGIC;
            r2_sel_out          : OUT STD_LOGIC;
            sp_type_out         : OUT STD_LOGIC;
            sp_wb_out           : OUT STD_LOGIC;
            swap_out            : OUT STD_LOGIC;
            wb_sel_out          : OUT STD_LOGIC_VECTOR(1 DOWNTO 0);
            mem_write_out       : OUT STD_LOGIC;
            mem_read_out        : OUT STD_LOGIC;
            io_write_out        : OUT STD_LOGIC;
            pc_from_memory_out  : OUT STD_LOGIC;
            write_data_sel_out  : OUT STD_LOGIC_VECTOR(1 DOWNTO 0);
            io_read_out         : OUT STD_LOGIC;
            reg_write_out       : OUT STD_LOGIC;
            is_std_out          : OUT STD_LOGIC;
            is_branch_out       : OUT STD_LOGIC;
            branch_type_out     : OUT STD_LOGIC;
            stall_out           : OUT STD_LOGIC;
            instr_funct         : OUT STD_LOGIC_VECTOR(4 DOWNTO 0);
            sp_out              : OUT STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0);
            imm_ext_out         : OUT STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0);
            rsrc1               : OUT STD_LOGIC_VECTOR((REG_ADDR_WIDTH - 1) DOWNTO 0);
            rdst                : OUT STD_LOGIC_VECTOR((REG_ADDR_WIDTH - 1) DOWNTO 0);
            index_ext_out       : OUT STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0);
            r_data1             : OUT STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0);
            r_data2             : OUT STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0);
            dest                : OUT STD_LOGIC_VECTOR((REG_ADDR_WIDTH - 1) DOWNTO 0)
        );
    END COMPONENT;

    -- Testbench signals (inputs)
    SIGNAL clk                  : STD_LOGIC := '0';
    SIGNAL rst                  : STD_LOGIC := '0';
    SIGNAL sp_wb_data_in        : STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0) := (OTHERS => '0');
    SIGNAL wb_data              : STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0) := (OTHERS => '0');
    SIGNAL wb_addr              : STD_LOGIC_VECTOR(REG_ADDR_WIDTH - 1 DOWNTO 0) := (OTHERS => '0');
    SIGNAL reg_write_en         : STD_LOGIC := '0';
    SIGNAL sp_wb_sel            : STD_LOGIC := '0';
    SIGNAL instr_in             : STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0) := (OTHERS => '0');
    SIGNAL pc_in                : STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0) := (OTHERS => '0');
    SIGNAL id_ex_imm_op         : STD_LOGIC := '0';
    SIGNAL control_signals_sel  : STD_LOGIC := '0';  -- FROM HAZARD DETECTION
    SIGNAL swap_flag_in         : STD_LOGIC := '0';

    -- Output signals
    SIGNAL ccr_wb_out           : STD_LOGIC;
    SIGNAL imm_op_out           : STD_LOGIC;
    SIGNAL call_out             : STD_LOGIC;
    SIGNAL r2_sel_out           : STD_LOGIC;
    SIGNAL sp_type_out          : STD_LOGIC;
    SIGNAL sp_wb_out            : STD_LOGIC;
    SIGNAL swap_out             : STD_LOGIC;
    SIGNAL wb_sel_out           : STD_LOGIC_VECTOR(1 DOWNTO 0);
    SIGNAL mem_write_out        : STD_LOGIC;
    SIGNAL mem_read_out         : STD_LOGIC;
    SIGNAL io_write_out         : STD_LOGIC;
    SIGNAL pc_from_memory_out   : STD_LOGIC;
    SIGNAL write_data_sel_out   : STD_LOGIC_VECTOR(1 DOWNTO 0);
    SIGNAL io_read_out          : STD_LOGIC;
    SIGNAL reg_write_out        : STD_LOGIC;
    SIGNAL is_std_out           : STD_LOGIC;
    SIGNAL is_branch_out        : STD_LOGIC;
    SIGNAL branch_type_out      : STD_LOGIC;
    SIGNAL stall_out            : STD_LOGIC;
    SIGNAL instr_funct          : STD_LOGIC_VECTOR(4 DOWNTO 0);
    SIGNAL sp_out               : STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0);
    SIGNAL imm_ext_out          : STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0);
    SIGNAL rsrc1                : STD_LOGIC_VECTOR((REG_ADDR_WIDTH - 1) DOWNTO 0);
    SIGNAL rdst                 : STD_LOGIC_VECTOR((REG_ADDR_WIDTH - 1) DOWNTO 0);
    SIGNAL index_ext_out        : STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0);
    SIGNAL r_data1              : STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0);
    SIGNAL r_data2              : STD_LOGIC_VECTOR((WORD_SIZE - 1) DOWNTO 0);
    SIGNAL dest                 : STD_LOGIC_VECTOR((REG_ADDR_WIDTH - 1) DOWNTO 0);

    -- Test tracking
    SIGNAL test_done : BOOLEAN := FALSE;

BEGIN

    -- Clock generation
    clk_process : PROCESS
    BEGIN
        WHILE NOT test_done LOOP
            clk <= '0';
            WAIT FOR CLK_PERIOD / 2;
            clk <= '1';
            WAIT FOR CLK_PERIOD / 2;
        END LOOP;
        WAIT;
    END PROCESS;

    -- DUT instantiation
    DUT : decode_stage
    PORT MAP (
        clk                 => clk,
        rst                 => rst,
        sp_wb_data_in       => sp_wb_data_in,
        wb_data             => wb_data,
        wb_addr             => wb_addr,
        reg_write_en        => reg_write_en,
        sp_wb_sel           => sp_wb_sel,
        instr_in            => instr_in,
        pc_in               => pc_in,
        id_ex_imm_op        => id_ex_imm_op,
        control_signals_sel => control_signals_sel,
        swap_flag_in        => swap_flag_in,
        ccr_wb_out          => ccr_wb_out,
        imm_op_out          => imm_op_out,
        call_out            => call_out,
        r2_sel_out          => r2_sel_out,
        sp_type_out         => sp_type_out,
        sp_wb_out           => sp_wb_out,
        swap_out            => swap_out,
        wb_sel_out          => wb_sel_out,
        mem_write_out       => mem_write_out,
        mem_read_out        => mem_read_out,
        io_write_out        => io_write_out,
        pc_from_memory_out  => pc_from_memory_out,
        write_data_sel_out  => write_data_sel_out,
        io_read_out         => io_read_out,
        reg_write_out       => reg_write_out,
        is_std_out          => is_std_out,
        is_branch_out       => is_branch_out,
        branch_type_out     => branch_type_out,
        stall_out           => stall_out,
        instr_funct         => instr_funct,
        sp_out              => sp_out,
        imm_ext_out         => imm_ext_out,
        rsrc1               => rsrc1,
        rdst                => rdst,
        index_ext_out       => index_ext_out,
        r_data1             => r_data1,
        r_data2             => r_data2,
        dest                => dest
    );

    -- Stimulus process
    stim_proc : PROCESS
    BEGIN
        -- Initial reset (active low)
        rst <= '0';
        WAIT FOR 2 * CLK_PERIOD;
        rst <= '1';  -- Release reset
        WAIT FOR CLK_PERIOD;

        ------------------------------------------------------------------------
        -- TEST 1: SP Register Read and Write
        ------------------------------------------------------------------------
        REPORT "========== TEST 1: SP Register Read and Write ==========" SEVERITY NOTE;

        -- Write value to SP register (sp_wb_sel must be '1' to enable write)
        sp_wb_sel <= '1';
        sp_wb_data_in <= X"0000ABCD";
        WAIT FOR CLK_PERIOD;

        -- Verify SP output
        ASSERT sp_out = X"0000ABCD"
            REPORT "SP Write Test FAILED: Expected 0x0000ABCD, got " 
            SEVERITY ERROR;

        -- Update SP to a new value
        sp_wb_data_in <= X"00001234";
        WAIT FOR CLK_PERIOD;

        ASSERT sp_out = X"00001234"
            REPORT "SP Update Test FAILED: Expected 0x00001234, got " 
            SEVERITY ERROR;

        -- Test SP hold (sp_wb_sel = '0' should not update SP)
        sp_wb_sel <= '0';
        sp_wb_data_in <= X"FFFFFFFF";
        WAIT FOR CLK_PERIOD;

        ASSERT sp_out = X"00001234"
            REPORT "SP Hold Test FAILED: SP should remain 0x00001234 when sp_wb_sel=0, got "
            SEVERITY ERROR;

        sp_wb_sel <= '0';
        REPORT "TEST 1: SP Register Read/Write - PASSED" SEVERITY NOTE;

        ------------------------------------------------------------------------
        -- TEST 2: Register File Read and Write
        ------------------------------------------------------------------------
        REPORT "========== TEST 2: Register File Read and Write ==========" SEVERITY NOTE;

        -- Write to R1 via writeback
        reg_write_en <= '1';
        wb_addr <= "001";  -- R1 address
        wb_data <= X"DEADBEEF";
        WAIT FOR CLK_PERIOD;

        -- Write to R2 via writeback
        wb_addr <= "010";  -- R2 address
        wb_data <= X"CAFEBABE";
        WAIT FOR CLK_PERIOD;

        -- Write to R3 via writeback
        wb_addr <= "011";  -- R3 address
        wb_data <= X"12345678";
        WAIT FOR CLK_PERIOD;

        reg_write_en <= '0';

        -- Read R1 and R2 using instruction (NOP with register addresses set)
        -- Format: instr_in[23:21] = rsrc1, instr_in[20:18] = rsrc2
        instr_in <= OPC_NOP & "000" & "001" & "010" & "00" & "00000000000" & "00000";
        WAIT FOR CLK_PERIOD / 2;  -- Wait for combinational read

        ASSERT r_data1 = X"DEADBEEF"
            REPORT "Register R1 Read FAILED: Expected 0xDEADBEEF, got "
            SEVERITY ERROR;

        -- Note: For NOP, rdst is used based on operand2_address_sel which is '0' for NOP
        -- So it reads from Rsrc2 field (bits 20:18)
        ASSERT r_data2 = X"CAFEBABE"
            REPORT "Register R2 Read FAILED: Expected 0xCAFEBABE, got "
            SEVERITY ERROR;

        -- Read R3 via Rsrc1 field
        instr_in <= OPC_NOP & "000" & "011" & "001" & "00" & "00000000000" & "00000";
        WAIT FOR CLK_PERIOD / 2;

        ASSERT r_data1 = X"12345678"
            REPORT "Register R3 Read FAILED: Expected 0x12345678, got "
            SEVERITY ERROR;

        REPORT "TEST 2: Register File Read/Write - PASSED" SEVERITY NOTE;
        WAIT FOR CLK_PERIOD / 2;

        ------------------------------------------------------------------------
        -- TEST 3: No Operation (NOP)
        ------------------------------------------------------------------------
        REPORT "========== TEST 3: No Operation (NOP) ==========" SEVERITY NOTE;

        -- Issue NOP instruction (opcode = 00000)
        instr_in <= OPC_NOP & "000" & "000" & "000" & "00" & "00000000000" & "00000";
        id_ex_imm_op <= '0';
        control_signals_sel <= '0';
        WAIT FOR CLK_PERIOD / 2;

        -- NOP should not set reg_write, mem_write, mem_read, etc.
        ASSERT reg_write_out = '0'
            REPORT "NOP Test FAILED: reg_write should be 0"
            SEVERITY ERROR;

        ASSERT mem_write_out = '0'
            REPORT "NOP Test FAILED: mem_write should be 0"
            SEVERITY ERROR;

        ASSERT mem_read_out = '0'
            REPORT "NOP Test FAILED: mem_read should be 0"
            SEVERITY ERROR;

        ASSERT is_branch_out = '0'
            REPORT "NOP Test FAILED: is_branch should be 0"
            SEVERITY ERROR;

        ASSERT stall_out = '0'
            REPORT "NOP Test FAILED: stall should be 0"
            SEVERITY ERROR;

        ASSERT ccr_wb_out = '0'
            REPORT "NOP Test FAILED: ccr_wb should be 0"
            SEVERITY ERROR;

        REPORT "TEST 3: No Operation (NOP) - PASSED" SEVERITY NOTE;
        WAIT FOR CLK_PERIOD / 2;

        ------------------------------------------------------------------------
        -- TEST 4: Normal Control Signals
        ------------------------------------------------------------------------
        REPORT "========== TEST 4: Normal Control Signals ==========" SEVERITY NOTE;

        -- Test 4a: ALU Operation (ADD R1, R2, R3)
        REPORT "Test 4a: ALU ADD instruction" SEVERITY NOTE;
        instr_in <= OPC_ALU & "001" & "010" & "011" & "00" & "00000000000" & FUNC_ADD;
        swap_flag_in <= '0';
        WAIT FOR CLK_PERIOD / 2;

        ASSERT ccr_wb_out = '1'
            REPORT "ALU ADD: ccr_wb should be 1"
            SEVERITY ERROR;
        ASSERT reg_write_out = '1'
            REPORT "ALU ADD: reg_write should be 1"
            SEVERITY ERROR;
        ASSERT wb_sel_out = "00"
            REPORT "ALU ADD: wb_sel should be 00 (ALU result)"
            SEVERITY ERROR;
        ASSERT imm_op_out = '0'
            REPORT "ALU ADD: imm_op should be 0"
            SEVERITY ERROR;

        WAIT FOR CLK_PERIOD / 2;

        -- Test 4b: IADD (Immediate Add) - R1 = R2 + imm
        REPORT "Test 4b: IADD instruction" SEVERITY NOTE;
        instr_in <= OPC_IADD & "001" & "010" & "000" & "00" & "0000000000000100" ; -- imm = 4

        WAIT FOR CLK_PERIOD / 2;

        ASSERT imm_op_out = '1'
            REPORT "IADD: imm_op should be 1"
            SEVERITY ERROR;
        ASSERT r2_sel_out = '1'
            REPORT "IADD: r2_sel should be 1"
            SEVERITY ERROR;
        ASSERT reg_write_out = '1'
            REPORT "IADD: reg_write should be 1"
            SEVERITY ERROR;

        WAIT FOR CLK_PERIOD / 2;

        -- Test 4c: PUSH instruction
        REPORT "Test 4c: PUSH instruction" SEVERITY NOTE;
        instr_in <= OPC_PUSH & "001" & "000" & "000" & "00" & "00000000000" & "00000";
        WAIT FOR CLK_PERIOD / 2;

        ASSERT sp_type_out = '1'
            REPORT "PUSH: sp_type should be 1"
            SEVERITY ERROR;
        ASSERT sp_wb_out = '1'
            REPORT "PUSH: sp_wb should be 1"
            SEVERITY ERROR;
        ASSERT mem_write_out = '1'
            REPORT "PUSH: mem_write should be 1"
            SEVERITY ERROR;
        ASSERT reg_write_out = '0'
            REPORT "PUSH: reg_write should be 0"
            SEVERITY ERROR;

        WAIT FOR CLK_PERIOD / 2;

        -- Test 4d: POP instruction
        REPORT "Test 4d: POP instruction" SEVERITY NOTE;
        instr_in <= OPC_POP & "001" & "000" & "000" & "00" & "00000000000" & "00000";
        WAIT FOR CLK_PERIOD / 2;

        ASSERT sp_wb_out = '1'
            REPORT "POP: sp_wb should be 1"
            SEVERITY ERROR;
        ASSERT mem_read_out = '1'
            REPORT "POP: mem_read should be 1"
            SEVERITY ERROR;
        ASSERT reg_write_out = '1'
            REPORT "POP: reg_write should be 1"
            SEVERITY ERROR;
        ASSERT wb_sel_out = "10"
            REPORT "POP: wb_sel should be 10 (from memory)"
            SEVERITY ERROR;

        WAIT FOR CLK_PERIOD / 2;

        -- Test 4e: LDM (Load Immediate) instruction
        REPORT "Test 4e: LDM instruction" SEVERITY NOTE;
        instr_in <= OPC_LDM & "001" & "000" & "000" & "00" & "1111111111111111"; -- imm = -1 (0xFFFF)
        WAIT FOR CLK_PERIOD / 2;

        ASSERT imm_op_out = '1'
            REPORT "LDM: imm_op should be 1"
            SEVERITY ERROR;
        ASSERT reg_write_out = '1'
            REPORT "LDM: reg_write should be 1"
            SEVERITY ERROR;
        ASSERT wb_sel_out = "01"
            REPORT "LDM: wb_sel should be 01 (immediate)"
            SEVERITY ERROR;
        -- Check sign extension (16-bit 0xFFFF should extend to 32-bit 0xFFFFFFFF)
        ASSERT imm_ext_out = X"FFFFFFFF"
            REPORT "LDM: imm_ext_out should be sign-extended to 0xFFFFFFFF, got "
            SEVERITY ERROR;

        WAIT FOR CLK_PERIOD / 2;

        -- Test 4f: JMP instruction
        REPORT "Test 4f: JMP instruction" SEVERITY NOTE;
        instr_in <= OPC_JMP & "000" & "001" & "000" & "00" & "0000000000001000"; -- target in imm
        WAIT FOR CLK_PERIOD / 2;

        ASSERT is_branch_out = '1'
            REPORT "JMP: is_branch should be 1"
            SEVERITY ERROR;
        ASSERT branch_type_out = '0'
            REPORT "JMP: branch_type should be 0 (unconditional)"
            SEVERITY ERROR;
        ASSERT imm_op_out = '1'
            REPORT "JMP: imm_op should be 1"
            SEVERITY ERROR;

        WAIT FOR CLK_PERIOD / 2;

        -- Test 4g: CALL instruction
        REPORT "Test 4g: CALL instruction" SEVERITY NOTE;
        instr_in <= OPC_CALL & "000" & "001" & "000" & "00" & "0000000000010000"; -- target in imm
        WAIT FOR CLK_PERIOD / 2;

        ASSERT call_out = '1'
            REPORT "CALL: call should be 1"
            SEVERITY ERROR;
        ASSERT is_branch_out = '1'
            REPORT "CALL: is_branch should be 1"
            SEVERITY ERROR;
        ASSERT sp_type_out = '1'
            REPORT "CALL: sp_type should be 1 (push PC)"
            SEVERITY ERROR;
        ASSERT mem_write_out = '1'
            REPORT "CALL: mem_write should be 1"
            SEVERITY ERROR;

        WAIT FOR CLK_PERIOD / 2;

        -- Test 4h: IN instruction
        REPORT "Test 4h: IN instruction" SEVERITY NOTE;
        instr_in <= OPC_IN & "010" & "000" & "000" & "00" & "00000000000" & "00000";
        WAIT FOR CLK_PERIOD / 2;

        ASSERT io_read_out = '1'
            REPORT "IN: io_read should be 1"
            SEVERITY ERROR;
        ASSERT reg_write_out = '1'
            REPORT "IN: reg_write should be 1"
            SEVERITY ERROR;

        WAIT FOR CLK_PERIOD / 2;

        -- Test 4i: OUT instruction
        REPORT "Test 4i: OUT instruction" SEVERITY NOTE;
        instr_in <= OPC_OUT & "000" & "010" & "000" & "00" & "00000000000" & "00000";
        WAIT FOR CLK_PERIOD / 2;

        ASSERT io_write_out = '1'
            REPORT "OUT: io_write should be 1"
            SEVERITY ERROR;
        ASSERT reg_write_out = '0'
            REPORT "OUT: reg_write should be 0"
            SEVERITY ERROR;

        WAIT FOR CLK_PERIOD / 2;

        -- Test 4j: NOT instruction
        REPORT "Test 4j: NOT instruction" SEVERITY NOTE;
        instr_in <= OPC_NOT & "001" & "010" & "000" & "00" & "00000000000" & "00000";
        WAIT FOR CLK_PERIOD / 2;

        ASSERT ccr_wb_out = '1'
            REPORT "NOT: ccr_wb should be 1"
            SEVERITY ERROR;
        ASSERT reg_write_out = '1'
            REPORT "NOT: reg_write should be 1"
            SEVERITY ERROR;

        WAIT FOR CLK_PERIOD / 2;

        -- Test 4k: INC instruction
        REPORT "Test 4k: INC instruction" SEVERITY NOTE;
        instr_in <= OPC_INC & "001" & "010" & "000" & "00" & "00000000000" & "00000";
        WAIT FOR CLK_PERIOD / 2;

        ASSERT ccr_wb_out = '1'
            REPORT "INC: ccr_wb should be 1"
            SEVERITY ERROR;
        ASSERT reg_write_out = '1'
            REPORT "INC: reg_write should be 1"
            SEVERITY ERROR;

        WAIT FOR CLK_PERIOD / 2;

        -- Test 4l: HLT instruction (should stall)
        REPORT "Test 4l: HLT instruction" SEVERITY NOTE;
        instr_in <= OPC_HLT & "000" & "000" & "000" & "00" & "00000000000" & "00000";
        WAIT FOR CLK_PERIOD / 2;

        ASSERT stall_out = '1'
            REPORT "HLT: stall should be 1"
            SEVERITY ERROR;

        WAIT FOR CLK_PERIOD / 2;

        REPORT "TEST 4: Normal Control Signals - PASSED" SEVERITY NOTE;

        ------------------------------------------------------------------------
        -- TEST 5: Control Signal Muxing with id_ex_imm_op and control_signals_sel
        ------------------------------------------------------------------------
        REPORT "========== TEST 5: Control Signal Muxing ==========" SEVERITY NOTE;

        -- Test 5a: When id_ex_imm_op = '1', all control outputs should be zeroed
        REPORT "Test 5a: id_ex_imm_op = 1 should zero control signals" SEVERITY NOTE;
        instr_in <= OPC_ALU & "001" & "010" & "011" & "00" & "00000000000" & FUNC_ADD;
        id_ex_imm_op <= '1';
        control_signals_sel <= '0';
        WAIT FOR CLK_PERIOD / 2;

        ASSERT ccr_wb_out = '0'
            REPORT "Mux Test 5a: ccr_wb should be 0 when id_ex_imm_op=1"
            SEVERITY ERROR;
        ASSERT reg_write_out = '0'
            REPORT "Mux Test 5a: reg_write should be 0 when id_ex_imm_op=1"
            SEVERITY ERROR;
        ASSERT mem_write_out = '0'
            REPORT "Mux Test 5a: mem_write should be 0 when id_ex_imm_op=1"
            SEVERITY ERROR;

        id_ex_imm_op <= '0';
        WAIT FOR CLK_PERIOD / 2;

        -- Test 5b: When control_signals_sel = '1' (from hazard detection), all control outputs should be zeroed
        REPORT "Test 5b: control_signals_sel = 1 should zero control signals (hazard)" SEVERITY NOTE;
        instr_in <= OPC_ALU & "001" & "010" & "011" & "00" & "00000000000" & FUNC_ADD;
        id_ex_imm_op <= '0';
        control_signals_sel <= '1';
        WAIT FOR CLK_PERIOD / 2;

        ASSERT ccr_wb_out = '0'
            REPORT "Mux Test 5b: ccr_wb should be 0 when control_signals_sel=1"
            SEVERITY ERROR;
        ASSERT reg_write_out = '0'
            REPORT "Mux Test 5b: reg_write should be 0 when control_signals_sel=1"
            SEVERITY ERROR;
        ASSERT mem_write_out = '0'
            REPORT "Mux Test 5b: mem_write should be 0 when control_signals_sel=1"
            SEVERITY ERROR;
        ASSERT is_branch_out = '0'
            REPORT "Mux Test 5b: is_branch should be 0 when control_signals_sel=1"
            SEVERITY ERROR;

        control_signals_sel <= '0';
        WAIT FOR CLK_PERIOD / 2;

        REPORT "TEST 5: Control Signal Muxing - PASSED" SEVERITY NOTE;

        ------------------------------------------------------------------------
        -- End of tests
        ------------------------------------------------------------------------
        REPORT "========================================" SEVERITY NOTE;
        REPORT "ALL TESTS COMPLETED SUCCESSFULLY" SEVERITY NOTE;
        REPORT "========================================" SEVERITY NOTE;

        test_done <= TRUE;
        WAIT;
    END PROCESS;

END ARCHITECTURE tb;
